    if (Array.isArray(parsed)) {
      const direct = normalizeFileEntries(parsed);
      if (direct.length) return direct;

      for (const entry of parsed) {
        const nested = extractFilesFromParsed(entry, depth + 1);
        if (nested.length) return nested;
