      const nestedCandidates = [
        parsed.response,
        parsed.output,
        parsed.result,
        parsed.text,
        parsed.data,
        parsed.body,
        parsed.message?.content,
        parsed.choices?.[0]?.message?.content,
        parsed.choices?.[0]?.delta?.content,
        parsed.choices?.[0]?.text,
