    const source = String(text || '');

    const tick3 = String.fromCharCode(96, 96, 96);
    const regexBacktick = new RegExp(`${tick3}(?:json)?\\s*([\\s\\S]*?)\\s*${tick3}`, 'gi');
    for (const match of source.matchAll(regexBacktick)) {
      const candidate = String(match[1] || '').trim();
      if (candidate) candidates.push(candidate);
    }

    const regexTilde = /~~~(?:json)?\s*([\s\S]*?)\s*~~~/gi;
    for (const match of source.matchAll(regexTilde)) {
      const candidate = String(match[1] || '').trim();
      if (candidate) candidates.push(candidate);
    }

    return candidates;
  }

  function parseJsonPayload(rawText) {
    const raw = String(rawText ?? '');
    if (!raw.trim()) {
      return { files: [], parseError: 'Empty model response.' };
    }

    const streamDecoded = normalizeStreamingText(raw);
    const text = String(streamDecoded || raw).trim();

    const candidates = [text, raw.trim()];
    candidates.push(...collectFencedCandidates(text));
    candidates.push(...collectFencedCandidates(raw));

    for (const source of [text, raw]) {
      const start = source.indexOf('{');
      const end = source.lastIndexOf('}');
      if (start !== -1 && end !== -1 && end > start) {
        candidates.push(source.slice(start, end + 1));
      }
    }

    for (const candidate of candidates) {
      const parsed = parseMaybeJson(candidate);
      if (parsed === null) continue;

      const files = extractFilesFromParsed(parsed);
      if (files.length) {
        return { files, parseError: '' };
      }
    }

    const recovered = extractFilesFromMalformedPayload(text);
    if (recovered.length) {
      return { files: recovered, parseError: '' };
    }

    const recoveredRaw = extractFilesFromMalformedPayload(raw);
    if (recoveredRaw.length) {
      return { files: recoveredRaw, parseError: '' };
    }

    const lower = text.toLowerCase();
    if (lower.includes('no changes') || lower.includes('cannot fix') || lower.includes('not enough context')) {
      return { files: [], parseError: '' };
    }

    return { files: [], parseError: 'Could not parse compile-fix model output as JSON.' };
  }

  function decodeEscapedContent(rawValue) {
    const text = String(rawValue || '');

    if (!text.includes('\n') && /\\n|\\r/.test(text)) {
      return text
        .replace(/\\r\\n/g, '\n')
        .replace(/\\n/g, '\n')
        .replace(/\\r/g, '\n')
        .replace(/\\t/g, '\t');
    }

    return text
      .replace(/\r\n/g, '\n')
      .replace(/\r/g, '\n');
  }

  function normalizeGeneratedContent(contentValue) {
    if (typeof contentValue === 'string') return decodeEscapedContent(contentValue);
    if (contentValue === null || contentValue === undefined) return '';
    if (typeof contentValue === 'object') return JSON.stringify(contentValue, null, 2);
    return String(contentValue);
  }

  function compactText(value, maxChars) {
    const text = String(value ?? '');
    if (!text) return '';
    if (text.length <= maxChars) return text;
    return text.slice(0, maxChars);
  }

  const buildPromptItems = getNodeItemsSafe('FE - Build Validation Fix Prompt');

  return $input.all().map((item) => {
    const upstreamJson = buildPromptItems[0]?.json || {};
    const json = {
      ...upstreamJson,
      ...(item.json || {}),
    };

    const rawModelResponse = String(
      json.text
      ?? json.response
      ?? json.output
      ?? json.result
      ?? json.choices?.[0]?.message?.content
      ?? json.choices?.[0]?.delta?.content
      ?? json.choices?.[0]?.text
      ?? json.data?.choices?.[0]?.message?.content
      ?? json.data?.choices?.[0]?.delta?.content
      ?? json.data?.choices?.[0]?.text
      ?? json.body?.choices?.[0]?.message?.content
      ?? json.body?.choices?.[0]?.delta?.content
      ?? json.body?.choices?.[0]?.text
      ?? json.body
      ?? json.data
      ?? ''
    );

    const parsed = parseJsonPayload(rawModelResponse);
    const compileFixByPath = new Map();
    const ignoredCompileFixPaths = [];

    for (const file of parsed.files) {
      if (!file || typeof file !== 'object' || Array.isArray(file)) continue;
      const filePath = String(file.path || '').replace(/\\/g, '/').trim();
      if (!filePath.startsWith('frontend/')) {
        ignoredCompileFixPaths.push(filePath || '<empty>');
        continue;
      }
      if (compileFixByPath.has(filePath)) {
        compileFixByPath.delete(filePath);
      }
      compileFixByPath.set(filePath, normalizeGeneratedContent(file.content));
    }

    const compileFixFiles = Array.from(
      compileFixByPath.entries(),
      ([path, content]) => ({ path, content }),
    );
    const compileFixParsedPaths = compileFixFiles.map((file) => file.path);

    return {
      json: {
        ...json,
        compileFixParseError: parsed.parseError || '',
        compileFixRawResponse: compactText(rawModelResponse, 50000),
        compileFixRawResponseLength: rawModelResponse.length,
        compileFixFiles,
        compileFixParsedPaths,
        compileFixFileCount: compileFixFiles.length,
        compileFixHadChanges: compileFixFiles.length > 0,
        ignoredCompileFixPaths,
        ignoredCompileFixPathCount: ignoredCompileFixPaths.length,
      },
      binary: item.binary ?? {},
    };
  });
}

return beCleanCompileFixResponse();

function beApplyCompileFixes() {
  function isEditableProjectPath(pathValue) {
    const path = String(pathValue || '').trim().replace(/\\/g, '/');
    if (!path || !path.startsWith('frontend/')) return false;
    if (path === 'frontend/target' || path.startsWith('frontend/target/')) return false;
    if (path === 'frontend/bin' || path.startsWith('frontend/bin/')) return false;
    return true;
  }

  function normalizePathArray(value) {
    if (!Array.isArray(value)) return [];
    const seen = new Set();
    const normalized = [];
    for (const raw of value) {
      const path = String(raw || '').trim().replace(/\\/g, '/');
      if (!isEditableProjectPath(path)) continue;
      if (seen.has(path)) continue;
      seen.add(path);
      normalized.push(path);
    }
    return normalized;
  }

  function normalizeContent(contentValue) {
    if (typeof contentValue === 'string') return contentValue;
    if (contentValue === null || contentValue === undefined) return '';
    if (typeof contentValue === 'object') return JSON.stringify(contentValue, null, 2);
    return String(contentValue);
  }

  function normalizeGeneratedSourceContent(contentValue, filePath) {
    const path = String(filePath || '');
    let text = String(contentValue || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');

    if (/pom\.xml$/i.test(path) || /\.xml$/i.test(path)) {
      const looksEscapedXml =
        /^\s*<\?xml\s+version=\\"/m.test(text)
        || /<[^>\n]+\s+[A-Za-z_:][A-Za-z0-9_.:-]*=\\"/.test(text)
        || (text.includes('\\"') && /<\/?[A-Za-z]/.test(text));

      if (looksEscapedXml) {
        const ESCAPED_QUOTE_SENTINEL = '__N8N_KEEP_ESCAPED_XML_QUOTE__';
        text = text
          .replace(/\\\\\"/g, ESCAPED_QUOTE_SENTINEL)
          .replace(/\\\"/g, '"')
          .replace(new RegExp(ESCAPED_QUOTE_SENTINEL, 'g'), '\\"');
      }

      return text;
    }

    if (!/\.java$/i.test(path)) {
      return text;
    }

    // Important: do NOT globally unescape Java string literals, otherwise
    // JSON payload strings in tests (e.g. .content("{\\\"x\\\":...}")) become invalid Java.
    // Only unescape escaped quotes inside annotation lines where this issue occurs.
    if (!/\\\"/.test(text)) {
      return text;
    }

    const lines = text.split('\n');
    for (let i = 0; i < lines.length; i += 1) {
      const line = lines[i];
      const isAnnotationLine =
        /^\s*@\w+/.test(line)
        || /\b(name|value|path|strategy)\s*=\s*\\\"/.test(line);
      if (!isAnnotationLine) continue;
      lines[i] = line.replace(/\\\"/g, '"');
    }
    return lines.join('\n');
  }

  function isRuntimeDatasourceConfigPath(filePath) {
    const path = String(filePath || '').trim().replace(/\\/g, '/');
    return /^frontend\/src\/main\/resources\/application.*\.(ya?ml|properties)$/i.test(path);
  }

  function hasJavaCompileError(errorText) {
    const text = String(errorText || '');
    if (!text) return false;
    return [
      /compilation error/i,
      /cannot find symbol/i,
      /package\s+[A-Za-z0-9_.]+\s+does not exist/i,
      /unknown property/i,
      /incompatible types\s*:/i,
      /illegal character/i,
      /frontend[\\/].*src[\\/](main|test)[\\/].*\.(java|kt|groovy)/i,
    ].some((pattern) => pattern.test(text));
  }

  function hasCustomRepositoryOutage(errorText) {
    const text = String(errorText || '').toLowerCase();
    if (!text) return false;
    return (
      text.includes('repo.zalando')
      || text.includes('zalando (https://repo.zalando')
      || text.includes('forbidden (403)')
      || text.includes('name does not resolve')
      || text.includes('repo.spring.io/milestone')
      || text.includes('spring-milestones')
    );
  }

  function isPomChangeRelevant(errorText) {
    const rawText = String(errorText || '');
    const text = rawText.toLowerCase();
    if (!text) return false;

    const explicitPomOrResolutionMarkers = [
      'pom.xml',
      'non-parseable pom',
      'modelparseexception',
      'projectbuildingexception',
      'non-resolvable parent pom',
      'dependencies.dependency.version',
      'could not resolve dependencies',
      'could not collect dependencies',
      'could not resolve artifact',
      'failed to read artifact descriptor',
      'could not transfer artifact',
      'pluginresolutionexception',
      'name does not resolve',
      'forbidden (403)',
    ];

    if (explicitPomOrResolutionMarkers.some((marker) => text.includes(marker))) {
      return true;
    }

    const missingPackages = Array.from(
      rawText.matchAll(/package\s+([A-Za-z0-9_.]+)\s+does not exist/gi),
      (match) => String(match[1] || '').toLowerCase(),
    );

    const hasExternalMissingPackage = missingPackages.some((pkg) => {
      if (!pkg) return false;
      if (pkg.startsWith('com.example.')) return false;
      return /^(org|io|com|net|jakarta|javax)\./.test(pkg);
    });
    if (hasExternalMissingPackage) return true;

    const missingClassFiles = Array.from(
      rawText.matchAll(/class file for\s+([A-Za-z0-9_.]+)\s+not found/gi),
      (match) => String(match[1] || '').toLowerCase(),
    );

    return missingClassFiles.some((className) => {
      if (!className) return false;
      if (className.startsWith('com.example.')) return false;
      return /^(org|io|com|net|jakarta|javax)\./.test(className);
    });
  }

  function analyzePomPolicy(errorText, json) {
    const dependencyOrPomError = isPomChangeRelevant(errorText);
    const javaCompileError = hasJavaCompileError(errorText);
    const customRepoOutage = hasCustomRepositoryOutage(errorText);
    const compileErrorBucket = String(json.compileErrorBucket || '').toLowerCase();
    const errorBucketRepeatCount = Math.max(0, Number(json.errorBucketRepeatCount || 0));
    const mapstructLoopNeedsPom = Boolean(
      compileErrorBucket === 'java-mapstruct-unknown-property'
      && errorBucketRepeatCount >= 2
    );

    const dependencyDrivenPomChange = dependencyOrPomError;
    const allowPom = dependencyDrivenPomChange || mapstructLoopNeedsPom;

    return {
      allowPom,
      javaCompileError,
      customRepoOutage,
      repeatingRepoOutage: customRepoOutage && errorBucketRepeatCount >= 2,
      pomRetryFlood: false,
      mapstructLoopNeedsPom,
    };
  }

  function hasDisallowedPomPatterns(content) {
    const text = String(content || '').toLowerCase();
    if (!text) return false;
    return (
      text.includes('repo.zalando')
      || text.includes('<artifactid>problem-throwable</artifactid>')
    );
  }

  function extractMissingDependencies(errorText) {
    const text = String(errorText || '');
    const found = [];
    const seen = new Set();

    const pattern = /dependency:\s+([A-Za-z0-9_.-]+):([A-Za-z0-9_.-]+):([A-Za-z0-9_.-]+):([A-Za-z0-9_.-]+)/gi;
    for (const match of text.matchAll(pattern)) {
      const groupId = String(match[1] || '').trim();
      const artifactId = String(match[2] || '').trim();
      const version = String(match[4] || '').trim();
      if (!groupId || !artifactId) continue;
      const key = `${groupId}:${artifactId}`;
      if (seen.has(key)) continue;
      seen.add(key);
      found.push({ groupId, artifactId, version });
    }

    return found;
  }

  function extractHistoricalMissingDependencies(history) {
    if (!Array.isArray(history)) return [];
    const merged = [];
    const seen = new Set();
    for (const entry of history.slice(-12)) {
      const text = String(entry?.errorSignature || '');
      for (const dep of extractMissingDependencies(text)) {
        const key = `${dep.groupId}:${dep.artifactId}`;
        if (seen.has(key)) continue;
        seen.add(key);
        merged.push(dep);
      }
    }
    return merged;
  }

  function removeDependencyBlocksByMatcher(pomContent, shouldRemove) {
    let removed = [];
    const next = String(pomContent || '').replace(/<dependency>[\s\S]*?<\/dependency>/gi, (block) => {
      const groupMatch = block.match(/<groupId>\s*([^<\s][^<]*)\s*<\/groupId>/i);
      const artifactMatch = block.match(/<artifactId>\s*([^<\s][^<]*)\s*<\/artifactId>/i);
      const groupId = String(groupMatch?.[1] || '').trim();
      const artifactId = String(artifactMatch?.[1] || '').trim();
      if (!groupId || !artifactId) return block;
      if (!shouldRemove(groupId, artifactId)) return block;
      removed.push(`${groupId}:${artifactId}`);
      return '';
    });

    removed = Array.from(new Set(removed));
    return { content: next, removed };
  }

  function removeBrokenRepositories(pomContent, errorText) {
    let content = String(pomContent || '');
    const removed = [];
    const text = String(errorText || '').toLowerCase();

    const repoPatterns = [
      { key: 'spring-milestones', marker: 'spring.io/milestone', pattern: /<repository>[\s\S]*?<url>\s*https?:\/\/repo\.spring\.io\/milestone\/?\s*<\/url>[\s\S]*?<\/repository>/gi },
      { key: 'repo.zalando', marker: 'repo.zalando', pattern: /<repository>[\s\S]*?<url>\s*https?:\/\/repo\.zalando[^<]*<\/url>[\s\S]*?<\/repository>/gi },
    ];

    for (const cfg of repoPatterns) {
      if (!text.includes(cfg.marker) && !text.includes('could not resolve dependencies')) continue;
      const before = content;
      content = content.replace(cfg.pattern, '');
      if (content !== before) removed.push(cfg.key);
    }

    return { content, removed: Array.from(new Set(removed)) };
  }

  function sanitizePomForDependencyResolution(pomContent, compileErrorContext, compileFixHistory) {
    const currentMissing = extractMissingDependencies(compileErrorContext);
    const historicalMissing = extractHistoricalMissingDependencies(compileFixHistory);

    const missingByGA = new Set();
    const unresolvedArtifactIds = new Set();
    for (const dep of [...historicalMissing, ...currentMissing]) {
      const groupId = String(dep.groupId || '').trim();
      const artifactId = String(dep.artifactId || '').trim();
      if (!groupId || !artifactId) continue;
      missingByGA.add(`${groupId}:${artifactId}`);
      unresolvedArtifactIds.add(artifactId);
    }

    let content = String(pomContent || '');
    const removedDependencies = [];

    const removedExact = removeDependencyBlocksByMatcher(content, (groupId, artifactId) => missingByGA.has(`${groupId}:${artifactId}`));
    content = removedExact.content;
    removedDependencies.push(...removedExact.removed);

    if (unresolvedArtifactIds.size > 0) {
      const removedByArtifact = removeDependencyBlocksByMatcher(content, (_groupId, artifactId) => unresolvedArtifactIds.has(artifactId));
      content = removedByArtifact.content;
      removedDependencies.push(...removedByArtifact.removed);
    }

    const removedRepos = removeBrokenRepositories(content, compileErrorContext);
    content = removedRepos.content;

    return {
      content,
      removedDependencies: Array.from(new Set(removedDependencies)),
      removedRepositories: removedRepos.removed,
      unresolvedArtifacts: Array.from(unresolvedArtifactIds),
    };
  }

  function canCreateNewSourceFile(filePath, compileErrorContext) {
    if (!/\.(java|kt|groovy)$/i.test(String(filePath || ''))) return true;
    const text = String(compileErrorContext || '');
    if (!text) return false;
    const basename = String(filePath || '').split('/').pop() || '';
    const className = basename.replace(/\.(java|kt|groovy)$/i, '');
    if (!className) return false;

    const explicitMissingTypeSignals = [
      /cannot find symbol/i,
      /class file for\s+[A-Za-z0-9_.]+\s+not found/i,
      /should be declared in file/i,
      /package\s+[A-Za-z0-9_.]+\s+does not exist/i,
    ];
    if (!explicitMissingTypeSignals.some((pattern) => pattern.test(text))) return false;
    return text.toLowerCase().includes(className.toLowerCase());
  }

  function buildSingleHunkDiff(path, beforeText, afterText) {
    const beforeLines = String(beforeText || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n').split('\n');
    const afterLines = String(afterText || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n').split('\n');

    let prefix = 0;
    while (
      prefix < beforeLines.length
      && prefix < afterLines.length
      && beforeLines[prefix] === afterLines[prefix]
    ) {
      prefix += 1;
    }

    let suffix = 0;
    while (
      suffix < (beforeLines.length - prefix)
      && suffix < (afterLines.length - prefix)
      && beforeLines[beforeLines.length - 1 - suffix] === afterLines[afterLines.length - 1 - suffix]
    ) {
      suffix += 1;
    }

    const beforeChanged = beforeLines.slice(prefix, beforeLines.length - suffix);
    const afterChanged = afterLines.slice(prefix, afterLines.length - suffix);

    const header = [
      `--- ${path}`,
      `+++ ${path}`,
      `@@ -${prefix + 1},${Math.max(1, beforeChanged.length)} +${prefix + 1},${Math.max(1, afterChanged.length)} @@`,
    ];

    const removed = beforeChanged.map((line) => `-${line}`);
    const added = afterChanged.map((line) => `+${line}`);
    return [...header, ...removed, ...added].join('\n');
  }

  function buildPatchPreview(records) {
    const MAX_FILES = 5;
    const MAX_CHARS = 16000;
    const chunks = [];
    let totalChars = 0;
    for (const record of records.slice(0, MAX_FILES)) {
      const diffText = buildSingleHunkDiff(record.path, record.beforeContent, record.afterContent);
      if (!diffText) continue;
      if (totalChars + diffText.length > MAX_CHARS) break;
      chunks.push(diffText);
      totalChars += diffText.length + 2;
    }
    return chunks.join('\n\n');
  }

  return $input.all().map((item) => {
    const json = item.json || {};
    const generatedFiles = Array.isArray(json.generatedFiles) ? json.generatedFiles : [];
    const compileFixFiles = Array.isArray(json.compileFixFiles) ? json.compileFixFiles : [];
    const compileFixAllowedPaths = normalizePathArray(json.compileFixAllowedPaths);
    const duplicateClassCandidateFiles = normalizePathArray(json.duplicateClassCandidateFiles);
    const hasDuplicateClassError = Boolean(json.hasDuplicateClassError) || duplicateClassCandidateFiles.length > 0;
    const duplicateClassCandidateSet = new Set(duplicateClassCandidateFiles);
    const compileErrorContext = String(json.compileErrorContext || '');
    const compileErrorBucket = String(json.compileErrorBucket || '').toLowerCase();
    const compileValidationStage = String(json.compileValidationStage || '').toLowerCase();
    const runtimeStageFailure = compileValidationStage === 'run' || compileErrorBucket === 'spring-boot-startup-failure';
    const compileFixHistory = Array.isArray(json.compileFixHistory) ? json.compileFixHistory : [];
    const compileFixUseSurgicalMode = Boolean(json.compileFixUseSurgicalMode);
    const compileFixUseWideRecoveryMode = Boolean(json.compileFixUseWideRecoveryMode);

    const pomPolicy = analyzePomPolicy(compileErrorContext, json);
    const pomChangeAllowed = pomPolicy.allowPom;
    const allowedScopeSet = new Set(compileFixAllowedPaths);

    const byPath = new Map();
    for (const file of generatedFiles) {
      const filePath = String(file?.path || '').trim();
      if (!filePath) continue;
      byPath.set(filePath, normalizeContent(file?.content));
    }

    const changedPaths = [];
    const changedDuplicateCandidatePaths = [];
    const ignoredPomFixPaths = [];
    const ignoredPomFixReasons = [];
    const ignoredScopeFixPaths = [];
    const ignoredScopeFixReasons = [];
    const runtimeConfigBlockedPaths = [];
    const runtimeConfigBlockedReasons = [];
    const autoRemovedUnresolvedDependencies = [];
    const autoRemovedRepositoryEntries = [];
    const changedRecords = [];
    let pomSanitizerTouched = false;

    const compileFixIsStuck = Boolean(json.compileFixIsStuck);
    const maxPatchFilesPerAttempt = hasDuplicateClassError
      ? 5
      : (compileFixUseWideRecoveryMode ? 10 : (compileFixUseSurgicalMode ? 3 : (compileFixIsStuck ? 4 : 5)));
    let acceptedPatchFileCount = 0;

    for (const patchFile of compileFixFiles) {
      const filePath = String(patchFile?.path || '').replace(/\\/g, '/').trim();
      if (!filePath) continue;
      if (!isEditableProjectPath(filePath)) {
        ignoredScopeFixPaths.push(filePath);
        ignoredScopeFixReasons.push('blocked_outside_frontend');
        continue;
      }
      if (allowedScopeSet.size > 0 && !allowedScopeSet.has(filePath)) {
        ignoredScopeFixPaths.push(filePath);
        ignoredScopeFixReasons.push('blocked_outside_allowed_scope');
        continue;
      }
      if (acceptedPatchFileCount >= maxPatchFilesPerAttempt) {
        ignoredScopeFixPaths.push(filePath);
        ignoredScopeFixReasons.push('blocked_patch_limit');
        continue;
      }

      const fileExists = byPath.has(filePath);
      if (!fileExists && !canCreateNewSourceFile(filePath, compileErrorContext)) {
        ignoredScopeFixPaths.push(filePath);
        ignoredScopeFixReasons.push('blocked_new_source_file_without_explicit_missing_type_error');
        continue;
      }

      let nextContent = normalizeContent(patchFile?.content);
      nextContent = normalizeGeneratedSourceContent(nextContent, filePath);

      if (runtimeStageFailure && isRuntimeDatasourceConfigPath(filePath)) {
        runtimeConfigBlockedPaths.push(filePath);
        runtimeConfigBlockedReasons.push('blocked_runtime_datasource_config_drift');
        ignoredScopeFixPaths.push(filePath);
        ignoredScopeFixReasons.push('blocked_runtime_datasource_config_drift');
        continue;
      }

      if (filePath === 'frontend/pom.xml') {
        if (!pomChangeAllowed) {
          ignoredPomFixPaths.push(filePath);
          ignoredPomFixReasons.push(
            (pomPolicy.javaCompileError && !pomPolicy.mapstructLoopNeedsPom)
              ? 'blocked_pom_change_due_to_java_compile_error'
              : 'blocked_pom_change_policy'
          );
          continue;
        }

        const shouldSanitizePom = compileErrorBucket === 'dependency-resolution' || compileErrorBucket.startsWith('dependency-');
        if (shouldSanitizePom) {
          const sanitized = sanitizePomForDependencyResolution(nextContent, compileErrorContext, compileFixHistory);
          nextContent = sanitized.content;
          if (sanitized.removedDependencies.length > 0 || sanitized.removedRepositories.length > 0) {
            pomSanitizerTouched = true;
          }
          autoRemovedUnresolvedDependencies.push(...sanitized.removedDependencies);
          autoRemovedRepositoryEntries.push(...sanitized.removedRepositories);
        }

        if (pomPolicy.customRepoOutage && hasDisallowedPomPatterns(nextContent)) {
          ignoredPomFixPaths.push(filePath);
          ignoredPomFixReasons.push(
            pomPolicy.repeatingRepoOutage
              ? 'blocked_pom_change_due_to_repeating_repo_outage'
              : 'blocked_pom_change_due_to_disallowed_repo_or_dependency'
          );
          continue;
        }
      }

      const previousContent = byPath.has(filePath) ? byPath.get(filePath) : null;
      if (previousContent !== nextContent) {
        changedPaths.push(filePath);
        changedRecords.push({
          path: filePath,
          beforeContent: previousContent == null ? '' : String(previousContent),
          afterContent: String(nextContent),
        });
        if (duplicateClassCandidateSet.has(filePath)) {
          changedDuplicateCandidatePaths.push(filePath);
        }
      }
      byPath.set(filePath, nextContent);
      acceptedPatchFileCount += 1;
    }

    const duplicateClassFixRejected = hasDuplicateClassError
      && duplicateClassCandidateSet.size > 0
      && changedDuplicateCandidatePaths.length === 0;

    const mergedGeneratedFiles = Array.from(byPath.entries()).map(([path, content]) => ({ path, content }));
    const mergedPlannedFiles = mergedGeneratedFiles.map((file) => ({ path: file.path }));
    const compileFixNoChangeCount = changedPaths.length
      ? 0
      : Number(json.compileFixNoChangeCount || 0) + 1;
    const compileFixLastPatchPreview = changedRecords.length ? buildPatchPreview(changedRecords) : '';

    return {
      json: {
        ...json,
        generatedFiles: mergedGeneratedFiles,
        generatedFilePaths: mergedGeneratedFiles.map((file) => file.path),
        generatedFileCountTotal: mergedGeneratedFiles.length,
        allPlannedFiles: mergedPlannedFiles,
        compileFixAppliedPaths: changedPaths,
        compileFixAppliedPathCount: changedPaths.length,
        ignoredPomFixPaths,
        ignoredPomFixCount: ignoredPomFixPaths.length,
        ignoredPomFixReasons,
        ignoredScopeFixPaths,
        ignoredScopeFixCount: ignoredScopeFixPaths.length,
        ignoredScopeFixReasons,
        runtimeConfigBlockedPaths,
        runtimeConfigBlockedCount: runtimeConfigBlockedPaths.length,
        runtimeConfigBlockedReasons,
        duplicateClassCandidateFiles,
        hasDuplicateClassError,
        changedDuplicateCandidatePaths,
        duplicateClassFixRejected,
        duplicateClassFixRejectedReason: duplicateClassFixRejected
          ? 'no_duplicate_candidate_file_changed'
          : '',
        pomChangeAllowed,
        pomSanitizerTouched,
        autoRemovedUnresolvedDependencies: Array.from(new Set(autoRemovedUnresolvedDependencies)),
        autoRemovedUnresolvedDependencyCount: Array.from(new Set(autoRemovedUnresolvedDependencies)).length,
        autoRemovedRepositoryEntries: Array.from(new Set(autoRemovedRepositoryEntries)),
        autoRemovedRepositoryEntryCount: Array.from(new Set(autoRemovedRepositoryEntries)).length,
        mapstructLoopNeedsPom: pomPolicy.mapstructLoopNeedsPom,
        compileFixIsStuck,
        compileFixUseSurgicalMode,
        compileFixUseWideRecoveryMode,
        maxPatchFilesPerAttempt,
        acceptedPatchFileCount,
        compileFixNoChangeCount,
        compileFixLastPatchPreview,
        compileFixLastPatchChangedFiles: changedRecords.map((entry) => entry.path),
      },
      binary: item.binary ?? {},
    };
  });
}

return beApplyCompileFixes();

function beAssembleFrontendZipInputs() {
    function getExtension(filePath) {
      const fileName = String(filePath || '').split('/').pop() || '';
      if (fileName === 'pom.xml') return 'xml';
      if (fileName === '.gitignore') return 'gitignore';
      const match = fileName.match(/\.([A-Za-z0-9]+)$/);
      return match ? match[1].toLowerCase() : 'txt';
    }
    function getMimeType(filePath) {
      const ext = getExtension(filePath);
      const mimeByExtension = {
        java: 'text/x-java-source',
        xml: 'application/xml',
        yaml: 'text/yaml',
        yml: 'text/yaml',
        json: 'application/json',
        properties: 'text/plain',
        md: 'text/markdown',
        txt: 'text/plain',
        sql: 'application/sql',
        csv: 'text/csv',
        gitignore: 'text/plain',
      };
      return mimeByExtension[ext] || 'text/plain';
    }
    function isIntentionallyEmptyFile(filePath) {
      const lower = String(filePath || '').toLowerCase();
      return lower.endsWith('/.gitkeep') || lower.endsWith('/.keep') || lower.endsWith('/.placeholder');
    }
    function normalizeContent(contentValue) {
      if (typeof contentValue === 'string') {
        return contentValue;
      }
      if (contentValue === null || contentValue === undefined) {
        return '';
      }
      if (typeof contentValue === 'object') {
        return JSON.stringify(contentValue, null, 2);
      }
      return String(contentValue);
    }
    const item = $input.first();
    if (!item) {
      throw new Error('No frontend generation state available for ZIP assembly.');
    }
    const json = item.json || {};
    const generatedFiles = Array.isArray(json.generatedFiles) ? json.generatedFiles : [];
    const remainingFiles = Array.isArray(json.remainingFiles) ? json.remainingFiles : [];
    if (remainingFiles.length > 0) {
      throw new Error('Cannot assemble frontend ZIP while files are still remaining.');
    }
    if (!generatedFiles.length) {
      throw new Error('No generated frontend files available to assemble ZIP.');
    }
    const binary = {};
    const manifest = [];
    generatedFiles.forEach((file, index) => {
      const filePath = String(file?.path || '').trim();
      const content = normalizeContent(file?.content);
      if (!filePath.startsWith('frontend/')) {
        throw new Error(`Generated frontend file path must start with "frontend/": ${filePath || '<empty>'}`);
      }
      // Empty files are allowed and must still be included in the assembled ZIP.
      const key = `file_${index}`;
      binary[key] = {
        data: Buffer.from(content, 'utf8').toString('base64'),
        mimeType: getMimeType(filePath),
        fileExtension: getExtension(filePath),
        fileName: filePath,
      };
      manifest.push({ path: filePath });
    });
    // Build structure from the actual ZIP payload (single source of truth).
    const zipManifestPaths = Object.values(binary)
      .map((entry) => String(entry?.fileName || '').trim())
      .filter((path) => path.startsWith('frontend/'));
    const structureManifest = Array.from(new Set(zipManifestPaths))
      .map((path) => ({ path }))
      .sort((a, b) => a.path.localeCompare(b.path));
    const frontendStructureObject = { files: structureManifest };
    const frontendStructure = JSON.stringify(frontendStructureObject);

    return [{
      json: {
        frontendRoot: 'frontend',
        fileCount: manifest.length,
        files: manifest,
        frontendStructure,
        frontendStructureObject,
        zipBinaryFields: Object.keys(binary).join(','),
      },
      binary,
    }];
  }
return beAssembleFrontendZipInputs();

