const item = $input.first() ?? { json: {}, binary: {} };
const currentJson = item.json ?? {};
const rawBinary = item.binary ?? {};

function getNodeItemSafe(nodeName) {
  if (typeof $items !== 'function') return null;
  try {
    return ($items(nodeName) || [])[0] || null;
  } catch {
    return null;
  }
}

function cleanJson(source) {
  const json = { ...(source ?? {}) };
  delete json.feedback;
  delete json.Feedback;
  delete json.Approved;
  delete json['Start Again'];
  delete json.reviewMode;
  return json;
}

function cleanBinary(source) {
  return Object.fromEntries(
    Object.entries(source ?? {})
      .filter(([key]) => !/^attachments?(?:_|$)/i.test(String(key)))
      .filter(([key]) => !String(key).endsWith('_firstIteration')),
  );
}

function normalizeFiles(value) {
  const files = Array.isArray(value) ? value : [];
  return files
    .map((entry) => {
      if (typeof entry === 'string') return { path: entry.trim() };
      if (entry && typeof entry === 'object') return { path: String(entry.path ?? '').trim() };
      return { path: '' };
    })
    .filter((entry) => entry.path);
}

const firstNode = getNodeItemSafe('FE - Prepare Information for First Iteration');
const firstJson = cleanJson(firstNode?.json ?? {});
const baseJson = cleanJson(currentJson);
const cleanCurrentBinary = cleanBinary(rawBinary);
const firstFiles = normalizeFiles(firstJson.files).length
  ? normalizeFiles(firstJson.files)
  : normalizeFiles(baseJson.firstIterationFiles);
const reviewerFeedback = [
  currentJson.reviewerFeedback,
  currentJson.feedback,
  currentJson.Feedback,
  baseJson.reviewerFeedback,
].map((value) => String(value ?? '').trim()).find((value) => value.length > 0) || '';

const outputJson = {
  ...baseJson,
  reviewerFeedback,
  reviewMode: '',
  firstIterationFiles: firstFiles,
  firstIterationFrontendStructure: String(firstJson.frontendStructure ?? baseJson.firstIterationFrontendStructure ?? '').trim(),
  firstIterationReviewRevisionNumber: Number(firstJson.revisionNumber ?? baseJson.firstIterationReviewRevisionNumber ?? baseJson.revisionNumber ?? 0) || 0,
  firstIterationReviewZipDownloadUrl: String(firstJson.zipDownloadUrl ?? baseJson.firstIterationReviewZipDownloadUrl ?? baseJson.zipDownloadUrl ?? '').trim(),
  firstIterationReviewZipDownloadToken: String(firstJson.zipDownloadToken ?? baseJson.firstIterationReviewZipDownloadToken ?? baseJson.zipDownloadToken ?? '').trim(),
  firstIterationReviewDownloadLinkHtml: String(firstJson.downloadLinkHtml ?? baseJson.firstIterationReviewDownloadLinkHtml ?? baseJson.downloadLinkHtml ?? '').trim(),
};

return [{
  json: outputJson,
  ...(Object.keys(cleanCurrentBinary).length ? { binary: cleanCurrentBinary } : {}),
}];
